class Solution:
    def numberOfSubstrings(self, s: str) -> int:
        a, b, c = 0, 0, 0
        res = 0
        for c in s:
            if c == 'a':
                a += 1
            elif c == 'b':
                b += 1
            else:
                c += 1
            if a > 0 and b > 0 and c > 0:
                res += a + b + c - 2
        return res
